// utils/waterfall-helper.ts
import { TestLogger, getLogger } from './test-logger';

export async function createWaterfall(
  page: Page,
  options: WaterfallOptions,
  logger: TestLogger = getLogger()
) {
  const source = 'helper:waterfall';
  logger.info(source, 'Starting waterfall creation', { options });
  // ... implementation
  logger.info(source, 'Waterfall created successfully');
}

step.before:
// tests/case/create-case.spec.ts
import { test, expect } from '@playwright/test';
import { PO_CaseV2 } from '../../page-objects/PO_CaseV2';

test('should create case successfully', async ({ page }) => {
  console.log('Starting test');
  const casePage = new PO_CaseV2(page);
  const caseId = await casePage.createCase(500);
  console.log('Case created:', caseId);
  expect(caseId).toBeTruthy();
});

step.after:
// tests/case/create-case.spec.ts
import { test, expect } from '../../fixtures/logger-fixture';
import { PO_CaseV2 } from '../../page-objects/PO_CaseV2';

test('should create case successfully', async ({ page, logger }) => {
  logger.info('test', 'Starting test');
  const casePage = new PO_CaseV2(page, logger);
  const caseId = await casePage.createCase(500);
  logger.info('test', 'Case created', { caseId });
  expect(caseId).toBeTruthy();
});
